# ===== Section 3 =====
doc.add_h1('\u4e09\u3001\u5404\u6559\u5b66\u73af\u8282\u8981\u6c42')

doc.add_h2('1. \u8bfe\u524d\u9884\u4e60')
doc.add_body('\u5b66\u751f\u5e94\u5728\u6bcf\u6b21\u8bbe\u8ba1\u8bfe\u524d\u9884\u4e60\u76f8\u5173\u7684\u89c4\u8303\u6761\u6587\u3001\u6559\u6750\u7ae0\u8282\u548c\u8bbe\u8ba1\u624b\u518c\u5185\u5bb9\uff0c\u4e86\u89e3\u672c\u6b21\u8bbe\u8ba1\u4efb\u52a1\u7684\u6280\u672f\u8981\u6c42\u548c\u89c4\u8303\u4f9d\u636e\u3002')

doc.add_h2('2. \u8bfe\u5802\u8bb2\u6388\u4e0e\u6307\u5bfc')
doc.add_body('\u6559\u5e08\u8bb2\u6388\u8bbe\u8ba1\u65b9\u6cd5\u3001\u89c4\u8303\u5e94\u7528\u8981\u70b9\u548c\u5e38\u89c1\u95ee\u9898\u5206\u6790\uff0c\u5168\u7a0b\u6307\u5bfc\u5b66\u751f\u5b8c\u6210\u8bbe\u8ba1\u4efb\u52a1\uff0c\u91c7\u7528\u542f\u53d1\u5f0f\u6559\u5b66\u5f15\u5bfc\u5b66\u751f\u72ec\u7acb\u601d\u8003\u3002\u9f13\u52b1\u5b66\u751f\u5229\u7528\u7ed3\u6784\u8bbe\u8ba1\u8f6f\u4ef6\uff08PKPM/YJK\uff09\u8fdb\u884c\u65b9\u6848\u9a8c\u8bc1\u548c\u4f18\u5316\u3002')

doc.add_h2('3. \u81ea\u4e3b\u8bbe\u8ba1\u4e0e\u8ba1\u7b97')
doc.add_body('\u5b66\u751f\u5e94\u5728\u89c4\u5b9a\u65f6\u95f4\u5185\u72ec\u7acb\u5b8c\u6210\u8bbe\u8ba1\u8ba1\u7b97\u4e66\u7684\u7f16\u5236\uff0c\u5305\u62ec\uff1a\u7ed3\u6784\u5e03\u7f6e\u65b9\u6848\u8bf4\u660e\uff1b\u8377\u8f7d\u8ba1\u7b97\u4e66\uff08\u542b\u8377\u8f7d\u6807\u51c6\u503c\u3001\u8bbe\u8ba1\u503c\u3001\u8377\u8f7d\u7ec4\u5408\uff09\uff1b\u697c\u76d6\u8bbe\u8ba1\u8ba1\u7b97\u4e66\uff08\u677f\u3001\u6b21\u6881\u3001\u4e3b\u6881\uff09\uff1b\u6846\u67b6\u5185\u529b\u5206\u6790\u8ba1\u7b97\u4e66\uff1b\u6846\u67b6\u622a\u9762\u8bbe\u8ba1\u4e0e\u914d\u7b4b\u8ba1\u7b97\u4e66\uff1b\u57fa\u7840\u8bbe\u8ba1\u8ba1\u7b97\u4e66\u3002')

doc.add_h2('4. \u65bd\u5de5\u56fe\u7ed8\u5236')
doc.add_body('\u5b66\u751f\u5e94\u5b8c\u6210\u4ee5\u4e0b\u65bd\u5de5\u56fe\u7ed8\u5236\uff08\u53ef\u91c7\u7528CAD\u6216BIM\u8f6f\u4ef6\uff09\uff1a\u6807\u51c6\u5c42\u7ed3\u6784\u5e03\u7f6e\u56fe\uff1b\u697c\u76d6\u914d\u7b4b\u56fe\uff08\u677f\u914d\u7b4b\u56fe\u3001\u6881\u914d\u7b4b\u56fe\uff09\uff1b\u6846\u67b6\u6881\u3001\u67f1\u914d\u7b4b\u8be6\u56fe\uff1b\u57fa\u7840\u5e73\u9762\u5e03\u7f6e\u56fe\u53ca\u914d\u7b4b\u8be6\u56fe\u3002')

doc.add_h2('5. \u6210\u679c\u7b54\u8fa9')
doc.add_body('\u5b66\u751f\u63d0\u4ea4\u5b8c\u6574\u7684\u8bbe\u8ba1\u6210\u679c\uff08\u8bbe\u8ba1\u8ba1\u7b97\u4e66+\u65bd\u5de5\u56fe+\u8bbe\u8ba1\u603b\u7ed3\u62a5\u544a\uff09\uff0c\u53c2\u52a0\u8bfe\u7a0b\u8bbe\u8ba1\u7b54\u8fa9\u3002\u7b54\u8fa9\u5185\u5bb9\u5305\u62ec\uff1a\u8bbe\u8ba1\u601d\u8def\u9610\u8ff0\u3001\u8bbe\u8ba1\u65b9\u6cd5\u4ecb\u7ecd\u3001\u4e3b\u8981\u6280\u672f\u53c2\u6570\u7684\u786e\u5b9a\u4f9d\u636e\u3001\u8bbe\u8ba1\u4e2d\u7684\u96be\u70b9\u53ca\u89e3\u51b3\u65b9\u6cd5\u3001\u81ea\u6211\u8bc4\u4ef7\u4e0e\u6539\u8fdb\u65b9\u5411\u3002')

